from flask import Flask, request, render_template, redirect, url_for, session, flash
import secrets
import hashlib
import time
from datetime import datetime, timedelta

app = Flask(__name__)
app.secret_key = secrets.token_hex(16)

# Mock user database
users = {
    "admin": {
        "password": hashlib.sha256("password123".encode()).hexdigest(),
        "mfa_secret": "SECRET1234567890"
    }
}

# Mock MFA tokens
mfa_tokens = {}

@app.route('/')
def index():
    if 'user_id' in session:
        return f"Welcome {session['user_id']}! <a href='/logout'>Logout</a>"
    return "Please <a href='/login'>login</a>"

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        
        if username in users:
            hashed_password = hashlib.sha256(password.encode()).hexdigest()
            if hashed_password == users[username]["password"]:
                # Store user in session temporarily
                session['user_id'] = username
                session['mfa_verified'] = False
                session['login_time'] = time.time()
                
                # Generate MFA token
                token = secrets.token_urlsafe(32)
                mfa_tokens[token] = {
                    'user_id': username,
                    'expires': datetime.now() + timedelta(minutes=5)
                }
                
                return redirect(url_for('verify_mfa', token=token))
        
        flash('Invalid username or password')
        return redirect(url_for('login'))
    
    return render_template('login.html')

@app.route('/verify-mfa')
def verify_mfa():
    token = request.args.get('token')
    
    if not token or token not in mfa_tokens:
        flash('Invalid or expired token')
        return redirect(url_for('login'))
    
    if datetime.now() > mfa_tokens[token]['expires']:
        flash('Token expired')
        return redirect(url_for('login'))
    
    # Store MFA verification status
    session['mfa_verified'] = True
    return render_template('mfa_verify.html', token=token)

@app.route('/verify-mfa-submit', methods=['POST'])
def verify_mfa_submit():
    token = request.form['token']
    mfa_code = request.form['mfa_code']
    
    if token not in mfa_tokens:
        flash('Invalid token')
        return redirect(url_for('login'))
    
    if datetime.now() > mfa_tokens[token]['expires']:
        flash('Token expired')
        return redirect(url_for('login'))
    
    # In a real app, verify the MFA code against the user's MFA secret
    # This is a simplified verification
    if mfa_code == "123456":  # Mock verification
        session['mfa_verified'] = True
        del mfa_tokens[token]
        return redirect(url_for('protected'))
    
    flash('Invalid MFA code')
    return redirect(url_for('verify_mfa', token=token))

@app.route('/protected')
def protected():
    if 'user_id' not in session or not session.get('mfa_verified'):
        flash('Access denied')
        return redirect(url_for('login'))
    
    return f"Protected content for {session['user_id']}"

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=True)